const pool = require\('./src/config/database'\);
const donationId = 37;
const userId = 9;

\(async \(\) => {
  try {
    console.log\('Testing approve donation logic...'\);

    const donation = await pool.query\(
      \\`SELECT d.*, f.user_id as fundraiser_owner
       FROM donations d
       JOIN fundraisers f ON d.fundraiser_id = f.id
       WHERE d.id = \\$1\\`,
      [donationId]
    \);

    console.log\('Donation:', JSON.stringify\(donation.rows[0], null, 2\)\);
    console.log\('User ID:', userId\);
    console.log\('Owner ID:', donation.rows[0].fundraiser_owner\);
    console.log\('Match:', donation.rows[0].fundraiser_owner === userId\);

    // Test the update query
    const client = await pool.connect\(\);
    try {
      await client.query\('BEGIN'\);
      console.log\('Transaction started'\);

      // Try to get donor stats
      const donorUpdate = await client.query\(
        \\`UPDATE users
         SET total_donated = total_donated + \\$1,
             people_helped = people_helped + 1
         WHERE id = \\$2
         RETURNING total_donated, people_helped\\`,
        [donation.rows[0].amount, donation.rows[0].donor_id]
      \);
      console.log\('Donor update result:', donorUpdate.rows[0]\);

      await client.query\('ROLLBACK'\);
      console.log\('Rolled back \(test only\)'\);
    } finally {
      client.release\(\);
    }

    process.exit\(0\);
  } catch \(error\) {
    console.error\('Error:', error.message\);
    console.error\('Stack:', error.stack\);
    process.exit\(1\);
  }
}\)\(\);
")

